parameters.new_string:
if (this.preferencesService) {
  const userId = (payload.metadata?.['userId'] as string) ?? payload.recipient;
  if (!this.preferencesService.shouldSendNotification(userId, payload)) {
    this.logger.info(
      `Notification blocked by user preferences: ${payload.type} for ${userId}`,
    );
    if (this.historyService) {
      const blockedId = generateNotificationId();
      this.historyService.logNotification(blockedId, payload, 'blocked');
    }
    return { success: true };
  }
}

